      MOCK_SERVER_HOST: 'http://localhost:${MOCK_SERVER_PORT}',
      BACKEND_API_HEALTH_CHECK_URL: '${MOCK_SERVER_HOST}/ci-health-check'
    }
  }
  const parsed = dotenvExpand.expand(dotenv).parsed

