node << 'EOF'
// Simulate what the code does
function _resolveEscapeSequences (value) {
  return value.replace(/\\\\$/g, '$')
}

function expandValue (value, processEnv, runningParsed) {
  const env = { ...runningParsed, ...processEnv }

  const regex = /(?<!\\)\${([^{}]+)}|(?<!\\)\$([A-Za-z_][A-Za-z0-9_]*)/g

  let result = value
  let match
  const seen = new Set()

  while ((match = regex.exec(result)) !== null) {
    seen.add(result)

    const [template, bracedExpression, unbracedExpression] = match
    const expression = bracedExpression || unbracedExpression

    const opRegex = /(:\+|\+|:-|-)/
    const opMatch = expression.match(opRegex)
    const splitter = opMatch ? opMatch[0] : null

    const r = expression.split(splitter)

    let defaultValue
    let value

    const key = r.shift()

    if ([':+', '+'].includes(splitter)) {
      defaultValue = env[key] ? r.join(splitter) : ''
      value = null
    } else {
      defaultValue = r.join(splitter)
      value = env[key]
    }

    if (value) {
      if (seen.has(value)) {
        result = result.replace(template, defaultValue)
      } else {
        result = result.replace(template, value)
      }
    } else {
      result = result.replace(template, defaultValue)
    }

    if (result === runningParsed[key]) {
      break
    }

    regex.lastIndex = 0
  }

  return result
}

// Test input
const input = '\\\\$ESCAPED';  // Two backslashes-dollar-ESCAPED
console.log('Input:', JSON.stringify(input), 'actual:', input);

// Step 1: expandValue (shouldn't match anything since \\$ is escaped)
const afterExpand = expandValue(input, {}, {});
console.log('After expandValue:', JSON.stringify(afterExpand), 'actual:', afterExpand);

// Step 2: _resolveEscapeSequences (should remove \\$)
const afterResolve = _resolveEscapeSequences(afterExpand);
console.log('After _resolveEscapeSequences:', JSON.stringify(afterResolve), 'actual:', afterResolve);

// Expected
console.log('');
console.log('Expected:', JSON.stringify('$ESCAPED'));
console.log('Match:', afterResolve === '$ESCAPED');
EOF

